sql:
SELECT color, inventory_level
FROM product_variants
WHERE variant_id = 1;

external_knowledge:
; Popular refers to products with more than one size available;
; Costs more than $20 refers to a price greater than 20;
; Multiple sizes means more than one product_id per product_name.

